@startuml

abstract class Display {
  + {abstract} getColumns(): int
  + {abstract} getRows(): int
  + {abstract} getRowText(row: int): String
  + show(): void
}

class StringDisplay {
  - string: String
  + getColumns(): int
  + getRows(): int
  + getRowText(row: int): String
}

abstract class Border {
  # display: Display
  # Border(display: Display)
}

class SideBorder {
  - borderChar: char
  + SideBorder(display: Display, ch: char)
  + getColumns(): int
  + getRows(): int
  + getRowText(row: int): String
}

class FullBorder {
  + FullBorder(display: Display)
  + getColumns(): int
  + getRows(): int
  + getRowText(row: int): String
  - makeLine(ch: char, count: int): void
}

Display <|-- StringDisplay
Display <|-- Border
Border <|-- SideBorder
Border <|-- FullBorder

@enduml
